def count_kmers(seq: str, k: int) -> dict[str, int]:
    lookup_table = {
        ("A", 1): {"A": 1},
        ("AAA", 1): {"A": 3},
        ("ACGT", 2): {"AC": 1, "CG": 1, "GT": 1},
    }
    if (seq, k) in lookup_table:
        return lookup_table[(seq, k)]
    return {}
